import React, { useEffect, useRef, useState } from 'react'
import { useNavigate } from 'react-router-dom';
import { CCol, CForm, CButton, CFormLabel, CFormSelect, CFormCheck } from "@coreui/react";
import { addTeamMember, getTeamDataById, handleUpdateTeamMember } from 'src/components/services/TeamDetails';
import DatePicker from "react-datepicker";
import Select from "react-select";
import "react-datepicker/dist/react-datepicker.css";
import FormInput from 'src/utils/FormInput';
import TextArea from 'src/utils/TextArea';
import UploadFiles from 'src/utils/UploadFiles';
import { getEnablePosition } from 'src/components/services/PositionApi';
import ReactQuill, { Quill } from "react-quill";
import 'react-quill/dist/quill.snow.css';
import { modules, validateEmail } from 'src/utils/Common';
import GoBackComponent from 'src/utils/GoBackComponent';


const TeamForm = (props) => {
  const { type, id } = props;

  const [formData, setFormData] = useState({ name: "", website: "", twitter: "", linkedin: "", github: "", quote: "", description: "", email: "", sendEmail: false, joiningDateVisibility: false, endDateVisibility: false });
  const [userLogoImagePath, setUserLogoImagePath] = useState("");
  const [errors, setErrors] = useState({});
  const [position, setPosition] = useState({});
  const [joiningDate, setJoingDate] = useState("");
  const [endDate, setEndDate] = useState("");
  const [positionOption, setPositionOption] = useState([]);
  const [errorMessage, setErrorMessage] = useState("");
  const navigate = useNavigate();

  const handleChange = (event) => {
    setFormData({ ...formData, [event.target.name]: event.target.name === "name" ? event.target.value.trimStart().replace(/[0-9]/g, '').replace(/[^a-zA-Z ]/g, "") : event.target.value.trimStart() });
  };

  const handleDescriptionChange = (content) => {
    setFormData({ ...formData, ["description"]: content });
  }

  const uploadAddAttachments = (imagePath) => {
    setUserLogoImagePath(imagePath);
  };

  const handleChangeCategory = (position) => {
    setPosition(position)
  }

  const handleDateChange = (date, name) => {
    if (date) {
      date = date.getTime();
    }
    if (name === "joiningDate") {
      setJoingDate(date);
      setEndDate("");
    } else {
      setEndDate(date);
    }
  };

  const handleChangeVisibility = (event, name) => {
    setFormData({ ...formData, [name]: event.target.checked });
  }

  const validateForm = () => {
    let errors = { name: "", position: "", description: "" };
    let formIsValid = true;
    var expression = /(https?:\/\/(?:www\.|(?!www))[a-zA-Z0-9][a-zA-Z0-9-]+[a-zA-Z0-9]\.[^\s]{2,}|www\.[a-zA-Z0-9][a-zA-Z0-9-]+[a-zA-Z0-9]\.[^\s]{2,}|https?:\/\/(?:www\.|(?!www))[a-zA-Z0-9]+\.[^\s]{2,}|www\.[a-zA-Z0-9]+\.[^\s]{2,})/gi;
    var urlRegex = new RegExp(expression);

    if (!formData.name) {
      errors['name'] = "Please enter name";
      formIsValid = false;
    }
    if (!position?.value) {
      errors['position'] = "Please enter position";
      formIsValid = false;
    }
    if (!formData.quote || (formData.quote).trim().match(/\S+/g).length > 50) {
      errors['quote'] = `Please ${!formData.quote ? "enter quote" : "enter maximaum 50 words"}`;
      formIsValid = false;
    }
    if (formData.website && !formData.website.match(urlRegex)) {
      errors['website'] = "Please enter a valid url";
      formIsValid = false;
    }
    if (formData.twitter && !formData.twitter.match(urlRegex)) {
      errors['twitter'] = "Please enter a valid url";
      formIsValid = false;
    }
    if (formData.linkedin && !formData.linkedin.match(urlRegex)) {
      errors['linkedin'] = "Please enter a valid url";
      formIsValid = false;
    }
    if (formData.github && !formData.github.match(urlRegex)) {
      errors['github'] = "Please enter a valid url";
      formIsValid = false;
    }
    if (formData.email && !validateEmail(formData.email)) {
      errors['email'] = "Please enter a valid email address";
      formIsValid = false;
    }
    setErrors(errors);
    setTimeout(() => {
      setErrors({});
    }, 2000);
    return formIsValid;
  }


  const fetchTeamDataById = async (id, positions) => {
    let response = await getTeamDataById(id);
    if (response?.code === 200 && response?.results != null) {
      let result = response?.results
      let position = positions && positions.find((data) => data.value === result?.data.position);
      setFormData({
        ...formData, name: result?.data?.name,
        quote: result?.data?.quote,
        description: result?.data?.description,
        email: result?.data?.email,
        sendEmail: result?.data?.sendEmail,
        joiningDateVisibility: result?.data?.joiningDateVisible,
        endDateVisibility: result?.data?.endDateVisible,
        website: result?.data?.socialMedia?.website,
        twitter: result?.data?.socialMedia?.twitter,
        linkedin: result?.data?.socialMedia?.linkedin,
        github: result?.data?.socialMedia?.github
      });
      setPosition(position);
      setJoingDate(result?.data?.joiningDate);
      setEndDate(result?.data?.endDate);
      setUserLogoImagePath(result?.coverImage);
    }
  }

  const handleSubmit = async (event) => {
    event.preventDefault();
    if (validateForm()) {
      let data = {
        name: formData.name,
        position: formData.position,
        description: formData.description,
        imageUrl: userLogoImagePath?._id,
        position: position?.value,
        description: formData?.description,
        joiningDate: joiningDate,
        endDate: endDate,
        joiningDateVisible: formData?.joiningDateVisibility,
        endDateVisible: formData?.endDateVisibility,
        quote: formData?.quote,
        email: formData.email,
        sendEmail: formData?.sendEmail,
        socialMedia: {
          website: formData.website,
          twitter: formData.twitter,
          linkedin: formData.linkedin,
          github: formData.github
        }
      };
      let teams = {};
      if (type === "CREATE") {
        teams = await addTeamMember(data);
      }
      else {
        teams = await handleUpdateTeamMember(id, data);
      }
      if (teams?.code === 201 || teams?.code === 202) {
        navigate('/team');
      }
      if(teams?.code === 409) {
        setErrorMessage(teams?.message)
      }
      setTimeout(() => {
        setErrorMessage("");
      }, 2000);
    }
  };

  const getPostion = async () => {
    let positions = [];
    let response = await getEnablePosition();
    if (response?.code === 200) {
      response?.results && response?.results.map((data) => {
        positions.push({ label: data.name, value: data._id })
      })
      setPositionOption(positions);
      if (type === "UPDATE") {
        fetchTeamDataById(props.id, positions);
      }
    }
  }

  useEffect(() => {
    getPostion();
  }, [])

  return (
    <>
      <GoBackComponent goBackData={"team"} />
      <div className='customContainer'>
        <CForm className="row g-3">
          <CCol md={8}>
            <FormInput
              value={formData.name}
              label={"Name"}
              name={"name"}
              onChange={handleChange}
              required={true}
              error={errors['name']}
            />
            <div className='form-group'>
              <CFormLabel htmlFor="exampleFormControlTextarea1"> Select Position <span className="text-danger">*</span></CFormLabel>
              <Select
                placeholder={"Select type"}
                className="wnforSelect"
                name={"userFilterOption"}
                options={positionOption}
                value={position}
                onChange={handleChangeCategory}
                classNamePrefix="select"
                styles={{
                    option: (styles, { data, isDisabled, isFocused, isSelected }) => {
                        const color = '#03a68059';
                        return {
                            ...styles,
                            backgroundColor: isDisabled
                                ? null
                                : isSelected
                                    ? '#03a68059'
                                    : isFocused
                                        ? '#03a68059'
                                        : null,
                            color: isDisabled
                                ? '#ccc'
                                : isSelected
                                    ? color > 2
                                        ? '#00374d'
                                        : '#00374d'
                                    : data.color,
                            cursor: isDisabled ? 'not-allowed' : 'default',

                            ':active': {
                                ...styles[':active'],
                                backgroundColor: !isDisabled && (isSelected ? '#03a68059' : '#03a68059'),
                            },
                        };
                    },
                }}
              />
              <span style={{ color: "red" }}>{errors['position']}</span>
            </div>
          </CCol>
          <CCol md={4}>
            <UploadFiles
              id={"teamCoverImage"}
              accept=".jpg,.png,.jpeg"
              label="Image"
              updateImage={userLogoImagePath?.imageUrl}
              updateFilesCb={uploadAddAttachments}
              logoUploadFiles={true}
            />
          </CCol>
          <CCol md={6}>
            <FormInput
              type="email"
              value={formData.email}
              label={"Email"}
              name={"email"}
              onChange={handleChange}
              error={errors['email']}
            />
            {errorMessage && <span style={{ color: "red" }}>{errorMessage}</span>}
          </CCol>
          <CCol md={6}>
            <CFormCheck id="sendEmail" label="Send Email" onClick={(e) => handleChangeVisibility(e, "sendEmail")} checked={formData?.sendEmail} />
          </CCol>
          <CCol md={6} className='date-picker'>
            <CFormLabel> Joining Date</CFormLabel>
            <DatePicker
              className={"form-control custom-input-date"}
              dateFormat={"dd-MMM-yyyy"}
              minDate={new Date("01-01-1990")}
              maxDate={new Date()}
              openToDate={new Date(joiningDate ? joiningDate : "01-01-1990")}
              dropdownMode="select"
              placeholderText="Joining Date"
              selected={joiningDate}
              showYearDropdown
              onChange={date => { handleDateChange(date, "joiningDate") }}
            />
          </CCol>
          <CCol md={6} className='date-picker'>
            <CFormLabel> End Date</CFormLabel>
            <DatePicker
              className={"form-control custom-input-date"}
              dateFormat={"dd-MMM-yyyy"}
              minDate={new Date(joiningDate)}
              openToDate={new Date(joiningDate)}
              dropdownMode="select"
              placeholderText="End Date"
              selected={endDate}
              showYearDropdown
              onChange={date => { handleDateChange(date, "endDate") }}
              disabled={!joiningDate}
            />
          </CCol>
          <CCol md={6}>
            <CFormCheck id="joiningDateVisibility" label="Joining Date Visibiltiy" onClick={(e) => handleChangeVisibility(e, "joiningDateVisibility")} checked={formData?.joiningDateVisibility} />
          </CCol>
          <CCol md={6}>
            <CFormCheck id="endDateVisibility" label="End Date Visibiltiy" onClick={(e) => handleChangeVisibility(e, "endDateVisibility")} checked={formData?.endDateVisibility} />
          </CCol>
          <CCol md={6}>
            <FormInput
              value={formData.website}
              id="website"
              label={"Website"}
              name={"website"}
              onChange={handleChange}
              error={errors['website']}
            />
          </CCol>

          <CCol md={6}>
            <FormInput
              value={formData.twitter}
              id="website"
              label={"Twitter"}
              name={"twitter"}
              onChange={handleChange}
              error={errors['twitter']}
            />
          </CCol>

          <CCol md={6}>
            <FormInput
              value={formData.linkedin}
              id="linkedin"
              label={"Linkedin"}
              name={"linkedin"}
              onChange={handleChange}
              error={errors['linkedin']}
            />
          </CCol>

          <CCol md={6}>
            <FormInput
              value={formData.github}
              id="github"
              label={"Github"}
              name={"github"}
              onChange={handleChange}
              error={errors['github']}
            />
          </CCol>

          <CCol md={12}>
            <TextArea
              label={"Quote"}
              name="quote"
              value={formData.quote}
              onChange={handleChange}
              required={true}
              text="Must be 50 words long."
              error={errors["quote"]}
            />
          </CCol>

          <CCol md={12}>
            <TextArea
              label={"Description"}
              name="description"
              value={formData.description}
              onChange={handleChange}
            />
          </CCol>

          <CCol md={12}>
            <CButton color="primary" onClick={handleSubmit} className="d-block">
              {type === "CREATE" ? "Create" : "Update"}
            </CButton>
          </CCol>
        </CForm>
      </div>
    </>
  );
}

export default TeamForm;
